const item = items[0];
let allDone = true;
const tasks = item.json.items;
const MAX_RETRIES = 3;

// [BUG-01 FIX] Usa la credenziale Header Auth dedicata per Kie.ai
// Configura una credenziale 'httpHeaderAuth' in n8n e assegnala al parametro credentials
// OPPURE imposta la API key manualmente qui (solo per sviluppo):
const KIE_API_KEY = this.getWorkflowStaticData('global').kie_auth || '';
const authHeaders = KIE_API_KEY ? { 'Authorization': KIE_API_KEY } : {};

for (const it of tasks) {
  if (it.state === 'success') continue;

  // [BUG-05 FIX] Retry per task falliti
  if (it.state === 'fail' && (it.retryCount || 0) >= MAX_RETRIES) continue;

  try {
    const res = await this.helpers.httpRequest({
      method: 'GET',
      url: `https://api.kie.ai/api/v1/jobs/recordInfo?taskId=${it.taskId}`,
      headers: authHeaders,
      json: true
    });

    const apiData = res.data;
    if (!apiData) { allDone = false; continue; }

    const state = apiData.state;
    if (state === 'success') {
      it.state = 'success';
      it.retryCount = 0;
      let finalUrl = null;
      try {
        if (apiData.resultJson) {
           const parsedResult = typeof apiData.resultJson === 'string' ? JSON.parse(apiData.resultJson) : apiData.resultJson;
           if (parsedResult && parsedResult.resultUrls && parsedResult.resultUrls.length > 0) { finalUrl = parsedResult.resultUrls[0]; }
        }
      } catch (err) { console.log('Errore parsing JSON:', err); }
      it.video_url = finalUrl;
    } else if (state === 'fail') {
      it.retryCount = (it.retryCount || 0) + 1;
      if (it.retryCount >= MAX_RETRIES) {
        it.state = 'fail';
        it.error = apiData.failMsg || 'Unknown error';
      } else {
        it.state = 'retry_pending';
        allDone = false;
      }
    } else {
      it.state = 'ing';
      allDone = false;
    }
  } catch (error) { 
    console.log('Polling error for task', it.taskId, error.message);
    allDone = false; 
  }
}

item.json.items = tasks;
item.json.allDone = allDone;
item.json.failCount = tasks.filter(t => t.state === 'fail').length;
item.json.successCount = tasks.filter(t => t.state === 'success').length;
return [item];

