const ideaData = $('Idea').first().json;
const dnaMap = {
  '__SUSPECT_DNA__': ideaData.Suspect_DNA,     
  '__OFFICER_DNA__': ideaData.Officer_DNA, 
  '__WITNESS_DNA__': ideaData.Witness_DNA    
};
function extractName(dnaString) {
  if (!dnaString) return "the person";
  let name = dnaString.replace(/^(Primary Officer|Secondary Officer|Subject S1|Subject S2|Witness|Manager|Ofc\.|Officer):\s*/i, '');
  name = name.split(/[(\:,]/)[0].trim();
  return name;
}
const items = $input.all();
return items.map(item => {
  let prompt = item.json.prompt;
  if (!prompt) return item;
  for (const [placeholder, fullDna] of Object.entries(dnaMap)) {
    if (!fullDna) continue;
    let cleanFullDna = fullDna.replace(/^(Primary Officer|Secondary Officer|Subject S1|Subject S2|Witness|Manager|Ofc\.|Officer):\s*/i, '');
    const shortName = extractName(fullDna);
    let counter = 0;
    prompt = prompt.replace(new RegExp(placeholder, 'g'), () => {
      counter++;
      return counter === 1 ? cleanFullDna : shortName;
    });
  }
  return {
    json: {
      ...item.json,
      prompt: prompt
    }
  };
});

